		}
		if _, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuidutils.MustNewUuidString(), userID, uuidutils.MustNewUuidString()); err != nil {
